// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// SERVICE ORDER · ItemsPanel
// Bottom section of the page. Three stacked strips:
//   1. Tabs        — Products | Billings | Inventory | History
//   2. Filter row  — funnel + label + dismissible Tag chips + kebab
//   3. Table       — checkbox + 9 product columns + per-row PanelMenu
//
// Selected row uses surface.active background plus an accent-300 left
// edge bar; row hover uses surface.hover. Sortable columns get a
// CaretUp/Down indicator on the active sort column.
// ============================================================

'use client';

import { useState } from 'react';
import { motion } from 'framer-motion';
import {
  Funnel,
  CaretUp,
  CaretDown,
  CaretUpDown,
  Pencil,
  Copy,
  Export,
  EyeSlash,
  ArrowsClockwise,
  Sliders,
} from '@phosphor-icons/react';

import { tokens } from '../../tokens';
import { CornerMarkers } from '../../components/CornerMarkers';
import { Checkbox } from '../../components/Checkbox';
import { IconButton } from '../../components/IconButton';
import { ProgressBar } from '../../components/ProgressBar';
import { Tag } from '../../components/Tag';
import { PanelMenu } from '../../components/PanelMenu';
import { Tooltip } from '../../components/Tooltip';
import { rowContainer, rowItem } from '../../components/lib/motion';
import { itemTabs, filterChips, productRows, initiallySelected } from './data';

function InsetDivider({ side = 'bottom' }) {
  return (
    <span
      aria-hidden
      style={{
        position: 'absolute',
        left: tokens.spacing[3],
        right: tokens.spacing[3],
        [side]: 0,
        height: '1px',
        background: tokens.color.border.subtle,
        pointerEvents: 'none',
      }}
    />
  );
}

// Inset row separator for tables — drawn via background-image because TR
// borders don't render under border-collapse:collapse.
const ROW_INSET_LINE = `linear-gradient(to right, transparent ${tokens.spacing[3]}, ${tokens.color.border.subtle} ${tokens.spacing[3]}, ${tokens.color.border.subtle} calc(100% - ${tokens.spacing[3]}), transparent calc(100% - ${tokens.spacing[3]}))`;
const rowSeparatorStyle = {
  backgroundImage: ROW_INSET_LINE,
  backgroundSize: '100% 1px',
  backgroundPosition: 'bottom',
  backgroundRepeat: 'no-repeat',
};

// ── Hover stylesheet — class rules so they win over inline styles ─
function HoverStyles() {
  return (
    <style>{`
      .so-tab        { transition: color 140ms ease; }
      .so-tab:hover  { color: ${tokens.color.text.primary} !important; }

      .so-row        { transition: background-color 100ms ease; cursor: pointer; }
      .so-row:hover  { background-color: ${tokens.color.surface.hover} !important; }
      .so-row.is-selected:hover { background-color: ${tokens.color.surface.active} !important; }

      .so-link       { transition: color 140ms ease; }
      .so-link:hover { color: ${tokens.color.text.primary} !important; text-decoration: underline; }

      .so-icon-btn   { transition: color 140ms ease, background-color 140ms ease; }
      .so-icon-btn:hover { color: ${tokens.color.text.primary} !important; background-color: ${tokens.color.surface.hover} !important; }
    `}</style>
  );
}

// ── Tab strip ──────────────────────────────────────────────────────
function TabStrip({ value, onChange }) {
  return (
    <div
      style={{
        position: 'relative',
        display: 'flex',
        alignItems: 'stretch',
        gap: tokens.spacing[1],
        padding: `0 ${tokens.spacing[3]}`,
      }}
    >
      <InsetDivider />
      {itemTabs.map((t) => {
        const active = value === t.id;
        return (
          <button
            key={t.id}
            type="button"
            className="so-tab"
            onClick={() => onChange(t.id)}
            style={{
              position: 'relative',
              display: 'inline-flex',
              alignItems: 'center',
              gap: tokens.spacing[2],
              padding: `${tokens.spacing[3]} ${tokens.spacing[3]}`,
              background: 'transparent',
              border: 'none',
              cursor: 'pointer',
              fontFamily: tokens.typography.fontMono,
              fontSize: tokens.typography.size.sm,
              fontWeight: active ? tokens.typography.weight.semibold : tokens.typography.weight.regular,
              color: active ? tokens.color.text.primary : tokens.color.text.muted,
              textTransform: 'uppercase',
              letterSpacing: tokens.typography.tracking.wider,
            }}
          >
            {t.label}
            <span
              style={{
                fontSize: tokens.typography.size.xs,
                color: tokens.color.text.faint,
                letterSpacing: tokens.typography.tracking.wide,
              }}
            >
              {t.count}
            </span>
            {active ? (
              <span
                aria-hidden
                style={{
                  position: 'absolute',
                  left: 0,
                  right: 0,
                  bottom: '-1px',
                  height: '2px',
                  background: tokens.color.accent[300],
                }}
              />
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

// ── Filter row (funnel + label + chips + kebab) ────────────────────
function FilterRow({ chips, onRemoveChip }) {
  return (
    <div
      style={{
        position: 'relative',
        display: 'flex',
        alignItems: 'center',
        gap: tokens.spacing[3],
        padding: `${tokens.spacing[3]} ${tokens.spacing[3]}`,
        minWidth: 0,
      }}
    >
      <InsetDivider />
      <Funnel weight="regular" size={14} color={tokens.color.text.muted} />
      <span
        style={{
          fontFamily: tokens.typography.fontMono,
          fontSize: tokens.typography.size.xs,
          color: tokens.color.text.muted,
          textTransform: 'uppercase',
          letterSpacing: tokens.typography.tracking.widest,
        }}
      >
        List of Products
      </span>

      <span
        aria-hidden
        style={{
          width: '1px',
          height: tokens.spacing[5],
          background: tokens.color.border.subtle,
          flexShrink: 0,
        }}
      />

      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: tokens.spacing[2],
          flex: 1,
          minWidth: 0,
          overflowX: 'auto',
        }}
      >
        {chips.map((label) => (
          <Tag key={label} variant="default" onClose={() => onRemoveChip(label)}>
            {label}
          </Tag>
        ))}
      </div>

      <Tooltip label="Refresh">
        <IconButton aria-label="Refresh" variant="ghost" size="md" icon={ArrowsClockwise} />
      </Tooltip>
      <Tooltip label="Configure">
        <IconButton aria-label="Configure" variant="ghost" size="md" icon={Sliders} />
      </Tooltip>
      <Tooltip label="Export">
        <IconButton aria-label="Export" variant="ghost" size="md" icon={Export} />
      </Tooltip>
    </div>
  );
}

// ── Sortable column header ────────────────────────────────────────
function ColHeader({ children, align = 'left', sort }) {
  // sort: 'asc' | 'desc' | 'sortable' | undefined
  const sortIcon =
    sort === 'asc'  ? <CaretUp     weight="bold" size={10} /> :
    sort === 'desc' ? <CaretDown   weight="bold" size={10} /> :
    sort === 'sortable' ? <CaretUpDown weight="regular" size={10} /> :
    null;

  const sorted = sort === 'asc' || sort === 'desc';

  return (
    <th
      style={{
        textAlign: align,
        verticalAlign: 'middle',
        padding: `${tokens.spacing[3]} ${tokens.spacing[3]}`,
        fontFamily: tokens.typography.fontMono,
        fontSize: tokens.typography.size.xs,
        fontWeight: tokens.typography.weight.medium,
        color: sorted ? tokens.color.text.primary : tokens.color.text.muted,
        textTransform: 'uppercase',
        letterSpacing: tokens.typography.tracking.widest,
        lineHeight: 1,
        whiteSpace: 'nowrap',
        verticalAlign: 'middle',
      }}
    >
      <span
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          gap: tokens.spacing[1],
          lineHeight: 1,
          height: '16px',
          color: 'inherit',
        }}
      >
        {children}
        {sortIcon ? (
          <span style={{ color: sorted ? tokens.color.text.primary : tokens.color.text.faint, display: 'inline-flex' }}>
            {sortIcon}
          </span>
        ) : null}
      </span>
    </th>
  );
}

function loadVariant(v) {
  if (v >= 85) return 'fault';
  if (v >= 60) return 'warning';
  return 'default';
}

// ── Table cell helper ──────────────────────────────────────────────
function Cell({ children, align = 'left', muted = false, mono = true, nowrap = true }) {
  return (
    <td
      style={{
        textAlign: align,
        verticalAlign: 'middle',
        padding: `${tokens.spacing[3]} ${tokens.spacing[3]}`,
        fontFamily: mono ? tokens.typography.fontMono : tokens.typography.fontSans,
        fontSize: tokens.typography.size.sm,
        color: muted ? tokens.color.text.secondary : tokens.color.text.primary,
        letterSpacing: tokens.typography.tracking.wide,
        whiteSpace: nowrap ? 'nowrap' : 'normal',
        lineHeight: 1,
      }}
    >
      {children}
    </td>
  );
}

// ── Composition ────────────────────────────────────────────────────
export function ItemsPanel() {
  const [tab, setTab] = useState('products');
  const [chips, setChips] = useState(filterChips);
  const [selected, setSelected] = useState(() => new Set(initiallySelected));

  const allSelected = productRows.length > 0 && productRows.every((r) => selected.has(r.id));

  function removeChip(label) {
    setChips((prev) => prev.filter((c) => c !== label));
  }

  function toggleRow(id) {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }

  function toggleAll(next) {
    setSelected(() => {
      if (next) return new Set(productRows.map((r) => r.id));
      return new Set();
    });
  }

  return (
    <div
      style={{
        position: 'relative',
        background: tokens.color.surface.raised,
        display: 'flex',
        flexDirection: 'column',
        flex: 1,
        minHeight: 0,
      }}
    >
      <CornerMarkers />
      <HoverStyles />

      <TabStrip value={tab} onChange={setTab} />
      <FilterRow chips={chips} onRemoveChip={removeChip} />

      {/* Table — scrolls horizontally on narrow widths so the layout
          stays intact rather than collapsing columns. */}
      <div style={{ flex: 1, minHeight: 0, overflow: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'auto' }}>
          <thead>
            <tr style={rowSeparatorStyle}>
              <th
                style={{
                  width: tokens.spacing[8],
                  verticalAlign: 'middle',
                  padding: `${tokens.spacing[3]} 0 ${tokens.spacing[3]} ${tokens.spacing[3]}`,
                  lineHeight: 1,
                }}
              >
                <Checkbox
                  aria-label="Select all"
                  checked={allSelected}
                  onCheckedChange={toggleAll}
                />
              </th>
              <ColHeader>Current Load</ColHeader>
              <ColHeader sort="sortable">Order ID</ColHeader>
              <ColHeader sort="sortable">Part ID</ColHeader>
              <ColHeader sort="sortable">Source Location</ColHeader>
              <ColHeader sort="asc">Source Level</ColHeader>
              <ColHeader sort="sortable">Service Level</ColHeader>
              <ColHeader sort="sortable">GMM (Value)</ColHeader>
              <ColHeader sort="sortable" align="right">Total Volume</ColHeader>
              <th style={{ width: tokens.spacing[10] }} />
            </tr>
          </thead>
          <motion.tbody
            variants={rowContainer}
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true, amount: 0.2 }}
          >
            {productRows.map((r) => {
              const isSelected = selected.has(r.id);
              return (
                <motion.tr
                  key={r.id}
                  variants={rowItem}
                  className={`so-row${isSelected ? ' is-selected' : ''}`}
                  onClick={() => toggleRow(r.id)}
                  style={{
                    backgroundColor: isSelected ? tokens.color.surface.active : 'transparent',
                    ...rowSeparatorStyle,
                    boxShadow: isSelected ? `inset 2px 0 0 0 ${tokens.color.accent[300]}` : undefined,
                  }}
                >
                  <td
                    style={{
                      padding: `${tokens.spacing[3]} 0 ${tokens.spacing[3]} ${tokens.spacing[3]}`,
                      verticalAlign: 'middle',
                    }}
                    onClick={(e) => e.stopPropagation()}
                  >
                    <Checkbox
                      aria-label={`Select ${r.id}`}
                      checked={isSelected}
                      onCheckedChange={() => toggleRow(r.id)}
                    />
                  </td>
                  <Cell>
                    <div style={{ zoom: 0.5 }}>
                      <ProgressBar value={r.load} variant={loadVariant(r.load)} />
                    </div>
                  </Cell>
                  <Cell muted>{r.id}</Cell>
                  <Cell>{r.part}</Cell>
                  <Cell muted>{r.source}</Cell>
                  <Cell>{r.sourceLvl}%</Cell>
                  <Cell>{r.serviceLvl}</Cell>
                  <Cell>{r.gmm}</Cell>
                  <Cell align="right">{r.total}</Cell>
                  <td
                    style={{
                      verticalAlign: 'middle',
                      padding: `${tokens.spacing[2]} ${tokens.spacing[2]}`,
                    }}
                    onClick={(e) => e.stopPropagation()}
                  >
                    <PanelMenu
                      ariaLabel={`Actions for ${r.id}`}
                      items={[
                        { label: 'Edit',      icon: Pencil, onSelect: () => {} },
                        { label: 'Duplicate', icon: Copy,   onSelect: () => {} },
                        { label: 'Export',    icon: Export, onSelect: () => {} },
                        { type: 'separator' },
                        { label: 'Hide',      icon: EyeSlash, destructive: true, onSelect: () => {} },
                      ]}
                    />
                  </td>
                </motion.tr>
              );
            })}
          </motion.tbody>
        </table>
      </div>
    </div>
  );
}

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
// ============================================================
// SERVICE ORDER · OrderMetadataPanel
// Left panel — standalone. Header strip with Order ID, countdown
// timer, Edit + Generate Report; below it the 3-col × 3-row
// contract metadata grid.
// ============================================================

'use client';

import { useEffect, useRef, useState } from 'react';
import { Pencil, FileText, Clock, CaretDown } from '@phosphor-icons/react';
import { tokens } from '../../tokens';
import { CornerMarkers } from '../../components/CornerMarkers';

// Inset divider — 12px from each edge. Sibling of content inside a position:relative parent.
function InsetDivider({ side = 'bottom' }) {
  return (
    <span
      aria-hidden
      style={{
        position: 'absolute',
        left: tokens.spacing[3],
        right: tokens.spacing[3],
        [side]: 0,
        height: '1px',
        background: tokens.color.border.subtle,
        pointerEvents: 'none',
      }}
    />
  );
}

const FOLLOW_UP_OPTIONS = ['02:00 Hours', '04:00 Hours', '12:00 Hours', '24:00 Hours'];

function FollowUpDropdown({ initial = '24:00 Hours' }) {
  const [value, setValue] = useState(initial);
  const [open, setOpen] = useState(false);
  const [custom, setCustom] = useState('');
  const wrapperRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => {
    if (!open) return;
    function handleDown(e) {
      if (wrapperRef.current && !wrapperRef.current.contains(e.target)) setOpen(false);
    }
    function handleKey(e) {
      if (e.key === 'Escape') setOpen(false);
    }
    document.addEventListener('mousedown', handleDown);
    document.addEventListener('keydown', handleKey);
    return () => {
      document.removeEventListener('mousedown', handleDown);
      document.removeEventListener('keydown', handleKey);
    };
  }, [open]);

  return (
    <div ref={wrapperRef} style={{ position: 'relative', width: '100%', maxWidth: '160px' }}>
      <button
        type="button"
        onClick={() => setOpen((o) => !o)}
        data-state={open ? 'open' : 'closed'}
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          gap: tokens.spacing[2],
          padding: `${tokens.spacing[2]} ${tokens.spacing[3]}`,
          background: open ? tokens.color.surface.hover : tokens.color.surface.overlay,
          border: `${tokens.border.thin} ${open ? tokens.color.border.bright : tokens.color.border.base}`,
          cursor: 'pointer',
          fontFamily: tokens.typography.fontMono,
          fontSize: tokens.typography.size.sm,
          color: tokens.color.text.primary,
          letterSpacing: tokens.typography.tracking.wide,
          width: '100%',
          transition: 'background 140ms ease, border-color 140ms ease',
        }}
      >
        {value}
        <CaretDown
          weight="regular"
          size={12}
          style={{ transform: open ? 'rotate(180deg)' : 'rotate(0deg)', transition: 'transform 140ms ease', flexShrink: 0 }}
        />
      </button>

      {open && (
        <div
          style={{
            position: 'absolute',
            top: `calc(100% + ${tokens.spacing[2]})`,
            left: 0,
            right: 0,
            zIndex: 50,
            background: tokens.color.surface.raised,
            border: `${tokens.border.thin} ${tokens.color.border.base}`,
            boxShadow: `0 8px 32px ${tokens.color.surface.base}`,
          }}
        >
          <CornerMarkers />
          {FOLLOW_UP_OPTIONS.map((opt) => (
            <button
              key={opt}
              type="button"
              onClick={() => { setValue(opt); setCustom(''); setOpen(false); }}
              style={{
                display: 'block',
                width: '100%',
                padding: `${tokens.spacing[2]} ${tokens.spacing[3]}`,
                background: opt === value ? tokens.color.surface.active : 'transparent',
                border: 'none',
                cursor: 'pointer',
                fontFamily: tokens.typography.fontMono,
                fontSize: tokens.typography.size.sm,
                color: opt === value ? tokens.color.text.primary : tokens.color.text.secondary,
                letterSpacing: tokens.typography.tracking.wide,
                textAlign: 'left',
                transition: 'background 100ms ease, color 100ms ease',
              }}
              onMouseEnter={(e) => { if (opt !== value) { e.currentTarget.style.background = tokens.color.surface.hover; e.currentTarget.style.color = tokens.color.text.primary; }}}
              onMouseLeave={(e) => { if (opt !== value) { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = tokens.color.text.secondary; }}}
            >
              {opt}
            </button>
          ))}

          {/* Custom input — separated by a divider */}
          <div style={{ borderTop: `${tokens.border.thin} ${tokens.color.border.subtle}`, padding: tokens.spacing[2] }}>
            <input
              ref={inputRef}
              type="text"
              value={custom}
              onChange={(e) => setCustom(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && custom.trim()) {
                  const num = parseFloat(custom.trim());
                  const formatted = !isNaN(num) && num > 0
                    ? `${String(Math.floor(num)).padStart(2, '0')}:00 Hours`
                    : custom.trim();
                  setValue(formatted);
                  setCustom('');
                  setOpen(false);
                }
                if (e.key === 'Escape') setOpen(false);
              }}
              placeholder="Custom…"
              style={{
                display: 'block',
                width: '100%',
                padding: `${tokens.spacing[2]} ${tokens.spacing[3]}`,
                background: tokens.color.surface.overlay,
                border: `${tokens.border.thin} ${tokens.color.border.base}`,
                outline: 'none',
                fontFamily: tokens.typography.fontMono,
                fontSize: tokens.typography.size.sm,
                color: tokens.color.text.primary,
                letterSpacing: tokens.typography.tracking.wide,
                boxSizing: 'border-box',
              }}
              onFocus={(e) => { e.currentTarget.style.borderColor = tokens.color.border.bright; }}
              onBlur={(e) => { e.currentTarget.style.borderColor = tokens.color.border.base; }}
            />
          </div>
        </div>
      )}
    </div>
  );
}
import { Button } from '../../components/Button';
import { order, orderMetadata } from './data';

function parseSeconds(hms) {
  const [h, m, s] = hms.split(':').map(Number);
  return h * 3600 + m * 60 + s;
}

function formatSeconds(total) {
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  return [h, m, s].map((n) => String(n).padStart(2, '0')).join(':');
}

// ── Header strip ───────────────────────────────────────────────────
function HeaderStrip() {
  const [seconds, setSeconds] = useState(() => parseSeconds(order.timer));

  useEffect(() => {
    if (seconds <= 0) return;
    const id = setInterval(() => setSeconds((t) => Math.max(0, t - 1)), 1000);
    return () => clearInterval(id);
  }, [seconds <= 0]);

  return (
    <div
      style={{
        position: 'relative',
        display: 'flex',
        alignItems: 'center',
        gap: tokens.spacing[3],
        padding: `${tokens.spacing[4]} ${tokens.spacing[5]}`,
      }}
    >
      <InsetDivider />
      <span
        style={{
          fontFamily: tokens.typography.fontMono,
          fontSize: tokens.typography.size.xs,
          color: tokens.color.text.muted,
          textTransform: 'uppercase',
          letterSpacing: tokens.typography.tracking.widest,
        }}
      >
        Order
      </span>
      <span
        style={{
          fontFamily: tokens.typography.fontMono,
          fontSize: tokens.typography.size.lg,
          fontWeight: tokens.typography.weight.semibold,
          color: tokens.color.text.primary,
          letterSpacing: tokens.typography.tracking.wide,
        }}
      >
        {order.id}
      </span>

      {/* Timer chip — accent-300 because the value IS the measurement */}
      <span
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          gap: tokens.spacing[2],
          padding: `${tokens.spacing[1]} ${tokens.spacing[3]}`,
          background: tokens.color.surface.overlay,
          border: `${tokens.border.thin} ${tokens.color.border.base}`,
          fontFamily: tokens.typography.fontMono,
          fontSize: tokens.typography.size.sm,
          color: tokens.color.accent[300],
          letterSpacing: tokens.typography.tracking.wider,
        }}
      >
        <Clock weight="regular" size={14} />
        {formatSeconds(seconds)}
      </span>

      <div style={{ flex: 1 }} />

      <Button variant="outline" size="sm" icon={Pencil}>
        Edit
      </Button>
      <Button variant="default" size="sm" icon={FileText}>
        Generate Report
      </Button>
    </div>
  );
}

// ── Metadata cell ──────────────────────────────────────────────────
function MetaCell({ label, value, type }) {
  if (type === 'spacer') return <div />;

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: tokens.spacing[2], minWidth: 0 }}>
      <span
        style={{
          fontFamily: tokens.typography.fontMono,
          fontSize: tokens.typography.size.xs,
          color: tokens.color.text.muted,
          textTransform: 'uppercase',
          letterSpacing: tokens.typography.tracking.widest,
          lineHeight: 1,
        }}
      >
        {label}
      </span>

      {type === 'follow-up' ? (
        <FollowUpDropdown initial={value} />
      ) : (
        <span
          style={{
            fontFamily: tokens.typography.fontMono,
            fontSize: tokens.typography.size.sm,
            color: type === 'link' ? tokens.color.accent[300] : tokens.color.text.primary,
            letterSpacing: tokens.typography.tracking.wide,
            cursor: type === 'link' ? 'pointer' : 'default',
          }}
        >
          {value}
        </span>
      )}
    </div>
  );
}

// ── Composition ────────────────────────────────────────────────────
export function OrderMetadataPanel() {
  return (
    <div
      style={{
        position: 'relative',
        background: tokens.color.surface.raised,
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      <CornerMarkers />

      <HeaderStrip />

      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(3, 1fr)',
          columnGap: tokens.spacing[5],
          rowGap: tokens.spacing[5],
          padding: tokens.spacing[5],
          alignContent: 'start',
        }}
      >
        {orderMetadata.map((cell, i) => (
          <MetaCell key={`${cell.label}-${i}`} {...cell} />
        ))}
      </div>
    </div>
  );
}

// @ts-nocheck — design-systems/ is not type-checked (see design-systems/CLAUDE.md). Strip this after a proper typing pass.
